"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[421470],{168440:e=>{e.exports=JSON.parse('{"tag":{"label":"drying","permalink":"/dst-api-webdocs/docs/tags/drying","allTagsPath":"/dst-api-webdocs/docs/tags","count":12,"items":[{"id":"game-scripts/prefabs/desiccant","title":"Desiccant","description":"Manages the drying behavior and wetness state of desiccant items, interacting with the InventoryItemMoisture and MoistureAbsorberSource components to regulate item drying when attached to entities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/desiccant"},{"id":"game-scripts/components/dryable","title":"Dryable","description":"Marks an entity as capable of being dried and stores associated drying data, such as product yield, drying time, and associated build files for raw and dried states.","permalink":"/dst-api-webdocs/docs/game-scripts/components/dryable"},{"id":"game-scripts/components/dryingrack","title":"Dryingrack","description":"Manages drying behavior for items placed in a container, handling time-based drying, weather effects (rain/acid rain), and state persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/components/dryingrack"},{"id":"game-scripts/prefabs/firenettles","title":"Firenettles","description":"A consumable vegetable item that applies a temporary temperature-based debuff to non-plantkin eaters, which can be dried to produce a longer-lasting fuel source.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/firenettles"},{"id":"game-scripts/prefabs/froglegs","title":"Froglegs","description":"A raw meat food item that can be dried or cooked, granting basic nutrition and sanity penalty when eaten raw.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/froglegs"},{"id":"game-scripts/prefabs/meatrack","title":"Meatrack","description":"A structure that dries meat items when exposed to air and sunlight, and burns when ignited, destroying the dried food and producing ash instead.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/meatrack"},{"id":"game-scripts/prefabs/meatrack2","title":"Meatrack2","description":"Manages a multi-slot drying rack structure that processes raw meat and other edible items into dried versions using environmental conditions and optional salt collection.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/meatrack2"},{"id":"game-scripts/components/moistureabsorbersource","title":"Moistureabsorbersource","description":"Provides a source of drying capability for entities equipped with moisture absorption items.","permalink":"/dst-api-webdocs/docs/game-scripts/components/moistureabsorbersource"},{"id":"game-scripts/components/moistureabsorberuser","title":"Moistureabsorberuser","description":"Manages active moisture-absorbing items equipped or held by an entity and computes their combined drying effect.","permalink":"/dst-api-webdocs/docs/game-scripts/components/moistureabsorberuser"},{"id":"game-scripts/prefabs/moontree_blossom","title":"Moontree Blossom","description":"A perishable, stackable food item that can be dried into moon_tree_blossom_dried, used as a consumable item or decorative object.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moontree_blossom"},{"id":"game-scripts/prefabs/petals","title":"Petals","description":"A plant-based consumable item that can be dried into a different product and haunts under certain conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/petals"},{"id":"game-scripts/prefabs/tillweed","title":"Tillweed","description":"A perishable vegetable item that can be dried on a meat rack to produce tillweed_dried.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tillweed"}],"unlisted":false}}')}}]);